const DataPulse = () => {
    // Generate raw numbers instead of Vector3 objects to avoid prop-sync issues with read-only objects
    const points = useMemo(() => {
        const p = [];
        for (let i = 0; i < 50; i++) {
            p.push([
                (Math.random() - 0.5) * 10,
                (Math.random() - 0.5) * 10,
