    return (
        <ThreeGroup>
            {points.map((p, i) => (
                <ThreeMesh key={i} position={p as [number, number, number]}>
                    <ThreeSphereGeometry args={[0.02, 8, 8]} />
                    <ThreeMeshBasicMaterial color="#C5A059" transparent opacity={0.3} />
                </ThreeMesh>
            ))}
        </ThreeGroup>
    )
}

