import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Mail, Lock, User, ShieldCheck, ArrowRight, LogIn } from 'lucide-react';

interface UserData {
  username: string;
  email: string;
  tier: string;
  balance: number;
}

interface AuthProps {
  isOpen: boolean;
  onClose: () => void;
  onAuthSuccess: (user: UserData) => void;
}

export const AuthModal: React.FC<AuthProps> = ({ isOpen, onClose, onAuthSuccess }) => {
  const [isLogin, setIsLogin] = useState(false);
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1000));

    try {
      if (isLogin) {
        // Mock Login Logic
        const savedUsers = JSON.parse(localStorage.getItem('exza_users') || '[]');
        const user = savedUsers.find((u: any) => u.email === formData.email && u.password === formData.password);

        if (user) {
          const userData: UserData = {
            username: user.username,
            email: user.email,
            tier: user.tier || 'Basic',
            balance: user.balance || 0
          };
          localStorage.setItem('exza_current_user', JSON.stringify(userData));
          onAuthSuccess(userData);
          onClose();
        } else {
          setError('Invalid email or password');
        }
      } else {
        // Mock Registration Logic
        if (formData.password !== formData.confirmPassword) {
          setError('Passwords do not match');
          setLoading(false);
          return;
        }

        const savedUsers = JSON.parse(localStorage.getItem('exza_users') || '[]');
        if (savedUsers.some((u: any) => u.email === formData.email)) {
          setError('Email already registered');
          setLoading(false);
          return;
        }

        const newUser = {
          username: formData.username,
          email: formData.email,
          password: formData.password,
          tier: 'Basic',
          balance: 0
        };

        savedUsers.push(newUser);
        localStorage.setItem('exza_users', JSON.stringify(savedUsers));

        const userData: UserData = {
          username: newUser.username,
          email: newUser.email,
          tier: newUser.tier,
          balance: newUser.balance
        };
        localStorage.setItem('exza_current_user', JSON.stringify(userData));
        onAuthSuccess(userData);
        onClose();
      }
    } catch (err) {
      setError('An unexpected error occurred');
    } finally {
      setLoading(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-exza-dark/90 backdrop-blur-sm"
          />

          <motion.div
            initial={{ scale: 0.9, opacity: 0, y: 20 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.9, opacity: 0, y: 20 }}
            className="relative w-full max-w-md glass-panel rounded-[2rem] border border-exza-gold/20 p-8 shadow-2xl overflow-hidden"
          >
            {/* Background Glow */}
            <div className="absolute -top-24 -right-24 w-48 h-48 bg-exza-gold/10 blur-[80px] rounded-full pointer-events-none" />

            <div className="flex justify-between items-center mb-8">
              <div>
                <h2 className="text-3xl font-display font-bold text-white">
                  {isLogin ? 'Welcome Back' : 'Create Account'}
                </h2>
                <p className="text-stone-500 text-sm mt-1">
                  {isLogin ? 'Enter your credentials to access your portal' : 'Start your institutional earning journey'}
                </p>
              </div>
              <button onClick={onClose} className="p-2 hover:bg-white/5 rounded-full transition-colors text-stone-400">
                <X size={20} />
              </button>
            </div>

            {error && (
              <div className="mb-6 p-3 bg-red-500/10 border border-red-500/20 text-red-400 text-sm rounded-xl flex items-center gap-2">
                <ShieldCheck size={16} /> {error}
              </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-4">
              {!isLogin && (
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-stone-500 uppercase tracking-widest ml-1">Username</label>
                  <div className="relative">
                    <User className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-500" size={18} />
                    <input
                      required
                      type="text"
                      placeholder="Investor_01"
                      className="w-full bg-white/5 border border-white/10 rounded-xl py-3 pl-12 pr-4 text-white focus:border-exza-gold/50 outline-none transition-all"
                      value={formData.username}
                      onChange={e => setFormData({ ...formData, username: e.target.value })}
                    />
                  </div>
                </div>
              )}

              <div className="space-y-1">
                <label className="text-[10px] font-black text-stone-500 uppercase tracking-widest ml-1">Email Address</label>
                <div className="relative">
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-500" size={18} />
                  <input
                    required
                    type="email"
                    placeholder="name@institution.com"
                    className="w-full bg-white/5 border border-white/10 rounded-xl py-3 pl-12 pr-4 text-white focus:border-exza-gold/50 outline-none transition-all"
                    value={formData.email}
                    onChange={e => setFormData({ ...formData, email: e.target.value })}
                  />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-stone-500 uppercase tracking-widest ml-1">Password</label>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-500" size={18} />
                  <input
                    required
                    type="password"
                    placeholder="••••••••"
                    className="w-full bg-white/5 border border-white/10 rounded-xl py-3 pl-12 pr-4 text-white focus:border-exza-gold/50 outline-none transition-all"
                    value={formData.password}
                    onChange={e => setFormData({ ...formData, password: e.target.value })}
                  />
                </div>
              </div>

              {!isLogin && (
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-stone-500 uppercase tracking-widest ml-1">Confirm Password</label>
                  <div className="relative">
                    <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-500" size={18} />
                    <input
                      required
                      type="password"
                      placeholder="••••••••"
                      className="w-full bg-white/5 border border-white/10 rounded-xl py-3 pl-12 pr-4 text-white focus:border-exza-gold/50 outline-none transition-all"
                      value={formData.confirmPassword}
                      onChange={e => setFormData({ ...formData, confirmPassword: e.target.value })}
                    />
                  </div>
                </div>
              )}

              <button
                disabled={loading}
                type="submit"
                className="w-full py-4 bg-exza-gold text-exza-dark rounded-xl font-black text-lg hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-2 mt-4 shadow-lg shadow-exza-gold/20"
              >
                {loading ? 'Processing...' : (isLogin ? 'Login to Portal' : 'Register Account')}
                {!loading && <ArrowRight size={20} />}
              </button>
            </form>

            <div className="mt-8 text-center">
              <button
                onClick={() => setIsLogin(!isLogin)}
                className="text-sm text-stone-400 hover:text-white transition-colors"
              >
                {isLogin ? "Don't have an account? Register" : "Already have an account? Login"}
              </button>
            </div>

            <div className="mt-6 pt-6 border-t border-white/5 flex items-center justify-center gap-2 text-[10px] text-stone-600 uppercase font-black tracking-widest">
              <ShieldCheck size={12} /> SECURE 256-BIT ENCRYPTION
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

