        savedUsers.push(storageUser);
        localStorage.setItem('exza_users', JSON.stringify(savedUsers));
        localStorage.setItem('exza_current_user', JSON.stringify(newUser));

        onAuthSuccess(newUser);
        onClose();
      }
    } catch (err) {
      setError('Network synchronization error.');
    } finally {
