                        </button>
                        <button 
                          onClick={() => handleDeleteUser(u.email)}
                          className="p-2 text-stone-400 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-all"
                        >
                          <Trash2 size={18}/>
                        </button>
                      </div>
                    </td>
