                   >
                     Cancel
                   </button>
                   <button 
                    type="submit"
                    className="flex-1 py-4 bg-exza-gold text-exza-dark rounded-2xl font-black text-xs uppercase tracking-widest hover:scale-[1.02] active:scale-95 transition-all shadow-xl shadow-exza-gold/20 flex items-center justify-center gap-2"
                   >
                     <Save size={16}/> Commit Changes
                   </button>
                </div>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

