          <div className={`px-4 py-2 rounded-full border flex items-center gap-2 ${systemActive ? 'bg-emerald-500/10 border-emerald-500/50 text-emerald-400' : 'bg-red-500/10 border-red-500/50 text-red-400'}`}>
            <Activity size={16} /> {systemActive ? 'SYSTEM LIVE' : 'MAINTENANCE MODE'}
          </div>
          <button 
            onClick={() => setSystemActive(!systemActive)}
            className={`p-3 rounded-xl transition-all ${systemActive ? 'bg-red-500 text-white' : 'bg-emerald-500 text-white'}`}
          >
            {systemActive ? <Pause size={20}/> : <Play size={20}/>}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
        {[
          { label: 'System TVL', value: `$${stats.tvl.toLocaleString()}`, icon: Database, color: 'text-blue-500' },
          { label: 'Total Payouts', value: `$${stats.payouts.toLocaleString()}`, icon: DollarSign, color: 'text-emerald-500' },
          { label: 'Registered Nodes', value: stats.users, icon: Users, color: 'text-purple-500' },
          { label: 'Deployed Nodes', value: stats.nodes, icon: ShieldCheck, color: 'text-exza-gold' }
        ].map((s, i) => (
          <div key={i} className="glass-panel p-6 rounded-3xl border border-white/5 bg-white/5 shadow-xl">
            <div className={`p-3 w-fit bg-white/5 rounded-xl ${s.color} mb-4`}><s.icon size={24}/></div>
            <p className="text-[10px] font-black text-stone-500 uppercase tracking-widest">{s.label}</p>
            <p className="text-3xl font-display font-bold text-white">{s.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 glass-panel rounded-3xl border border-white/5 overflow-hidden shadow-2xl">
          <div className="p-6 border-b border-white/5 flex justify-between items-center bg-white/5">
            <h3 className="text-lg font-bold text-white flex items-center gap-2"><Users size={20} className="text-exza-gold"/> Institutional User Registry</h3>
            <span className="text-[10px] text-stone-500 font-black uppercase tracking-widest">{users.length} Active Accounts</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[600px]">
              <thead className="bg-white/5 text-[10px] uppercase font-black tracking-widest text-stone-500">
                <tr>
                  <th className="px-6 py-4">Node Profile</th>
                  <th className="px-6 py-4">USDT Equity</th>
                  <th className="px-6 py-4">Status</th>
                  <th className="px-6 py-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {users.map(u => (
                  <tr key={u.email} className="text-sm group hover:bg-white/5 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center text-exza-gold font-bold">
                          {u.username.charAt(0)}
                        </div>
                        <div>
                          <p className="text-white font-medium">{u.username}</p>
                          <p className="text-[10px] text-stone-500 font-mono">{u.email}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                       <p className="font-display font-bold text-white">${(u.balance || 0).toLocaleString()}</p>
                       <p className="text-[9px] text-stone-500 uppercase font-black">{u.tier} Tier</p>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-0.5 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                        u.status === 'Suspended' ? 'bg-red-500/10 border-red-500/30 text-red-500' :
                        (u.balance > 10000 || u.email === 'admin@exza.com') ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-500' : 
                        'bg-stone-500/10 border-stone-500/30 text-stone-500'
                      }`}>
                        {u.status || 'Verified'}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex gap-2 justify-end opacity-40 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => handleEditClick(u)}
                          className="p-2 text-stone-400 hover:text-white hover:bg-white/10 rounded-lg transition-all"
                        >
                          <Settings size={18}/>
                        </button>
                        <button 
                          onClick={() => handleDeleteUser(u.email)}
                          className="p-2 text-stone-400 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-all"
                        >
                          <Trash2 size={18}/>
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        <div className="space-y-6">
          <div className="glass-panel p-8 rounded-3xl border border-white/5">
            <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2"><Database size={20} className="text-blue-500"/> Real-time System Logs</h3>
            <div className="space-y-4">
              {[
                { time: '14:22', log: 'Database sync successful', type: 'info' },
                { time: '13:58', log: 'Backup node redundancy verified', type: 'info' },
                { time: '13:12', log: 'Batch reward distribution queued', type: 'warn' },
                { time: '12:05', log: 'New institutional account registered', type: 'success' },
                { time: '11:42', log: 'Encrypted ledger integrity check passed', type: 'success' }
              ].map((l, i) => (
                <div key={i} className="flex gap-3 text-[11px] items-center border-l-2 border-white/5 pl-4 py-1">
                  <span className="text-stone-600 font-mono">{l.time}</span>
                  <span className="text-stone-400">{l.log}</span>
                </div>
              ))}
            </div>
            <button className="w-full mt-6 py-3 border border-white/10 text-stone-500 rounded-xl text-[10px] font-black uppercase tracking-widest hover:text-white hover:bg-white/5 transition-all">Clear Logs</button>
          </div>

          <div className="glass-panel p-8 rounded-3xl border border-red-500/20 bg-red-500/5 shadow-2xl shadow-red-500/5">
             <div className="flex items-center gap-2 text-red-500 mb-4">
                <AlertTriangle size={24} />
                <h4 className="font-bold text-xl font-display">Quantum Halt</h4>
             </div>
             <p className="text-xs text-stone-500 mb-6 leading-relaxed">Safety Protocol 404: Immediately suspend all transactions, withdrawals, and node earning cycles across the entire network cluster.</p>
             <button className="w-full py-4 bg-red-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-red-600 transition-all shadow-xl shadow-red-500/20">TRIGGER EMERGENCY HALT</button>
          </div>
        </div>
      </div>

      {/* Edit User Modal */}
      <AnimatePresence>
        {isEditModalOpen && editingUser && (
          <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
            <motion.div 
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
