              className="absolute inset-0 bg-exza-dark/95 backdrop-blur-xl" 
            />
            <motion.div 
              initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }}
              className="relative w-full max-w-lg glass-panel rounded-[3rem] border border-exza-gold/20 p-10 shadow-2xl overflow-hidden"
            >
              <button 
                onClick={() => setIsEditModalOpen(false)}
                className="absolute top-6 right-6 text-stone-500 hover:text-white transition-colors"
