  const [withdrawAmount, setWithdrawAmount] = useState('');
  const [walletAddress, setWalletAddress] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [screenshot, setScreenshot] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const exzaEarnPackages = [
    { id: 1, name: 'Core Node', price: 50, ratio: '1x', dailyPct: 1.0, color: 'from-stone-500 to-stone-400', icon: Cpu },
    { id: 2, name: 'Silver Node', price: 100, ratio: '2x', dailyPct: 1.2, color: 'from-blue-400 to-cyan-500', icon: Star },
    { id: 3, name: 'Gold Node', price: 250, ratio: '5x', dailyPct: 1.5, color: 'from-amber-400 to-exza-gold', icon: Award },
    { id: 4, name: 'Platinum Node', price: 500, ratio: '10x', dailyPct: 1.8, color: 'from-indigo-500 to-purple-600', icon: ShieldCheck },
    { id: 5, name: 'Diamond Node', price: 1000, ratio: '20x', dailyPct: 2.0, color: 'from-rose-500 to-pink-600', icon: Gem },
