  };

  const handleMint = async (pkg: any) => {
    if (user.balance < pkg.price) {
      alert("Insufficient USDT balance for this Quantum Node.");
      return;
    }

    setIsMinting(true);
    await new Promise(r => setTimeout(r, 2000));

    const updatedUser = {
      ...user,
      balance: user.balance - pkg.price,
      nodes: [...(user.nodes || []), { 
        ...pkg, 
        purchaseDate: new Date().toISOString(), 
        status: 'Active' 
      }]
    };

    if (user.referredBy) {
      const savedUsers = JSON.parse(localStorage.getItem('exza_users') || '[]');
      const referrerL1 = savedUsers.find((u: any) => u.email === user.referredBy);

      if (referrerL1) {
        const comm = pkg.price * 0.10;
        referrerL1.balance += comm;
        referrerL1.referralEarnings = (referrerL1.referralEarnings || 0) + comm;

        const hasGoldPlus = (referrerL1.nodes || referrerL1.nfts || []).some((n: any) => n.price >= 250);
        if (hasGoldPlus && referrerL1.referredBy) {
          const referrerL2 = savedUsers.find((u: any) => u.email === referrerL1.referredBy);
          if (referrerL2) {
            const commL2 = pkg.price * 0.05;
            referrerL2.balance += commL2;
            referrerL2.referralEarnings = (referrerL2.referralEarnings || 0) + commL2;
          }
        }
      }
      localStorage.setItem('exza_users', JSON.stringify(savedUsers));
    }

    onUpdate(updatedUser);
    setIsMinting(false);
