import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Mail, Lock, User, ShieldCheck, ArrowRight, UserPlus } from 'lucide-react';
import { UserData } from '../App';

interface AuthProps {
  isOpen: boolean;
  onClose: () => void;
  onAuthSuccess: (user: UserData) => void;
}

export const AuthModal: React.FC<AuthProps> = ({ isOpen, onClose, onAuthSuccess }) => {
  const [isLogin, setIsLogin] = useState(true); // Default to login for convenience
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: '',
    referral: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Pre-initialize Admin account if no users exist
  useEffect(() => {
    const savedUsers = JSON.parse(localStorage.getItem('exza_users') || '[]');
    if (savedUsers.length === 0) {
      const adminUser = {
        username: 'System Admin',
        email: 'admin@exza.com',
        password: 'admin123',
        tier: 'Platinum',
        balance: 1000000,
        referralCode: 'ADMIN-CORE',
        referrals: 150,
        referralEarnings: 0,
        nodes: [],
        // Fix: Added missing transactions property to match UserData interface
        transactions: []
      };
      savedUsers.push(adminUser);
      localStorage.setItem('exza_users', JSON.stringify(savedUsers));
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    await new Promise(resolve => setTimeout(resolve, 1500));

    try {
      const savedUsers = JSON.parse(localStorage.getItem('exza_users') || '[]');

      if (isLogin) {
        const user = savedUsers.find((u: any) => u.email === formData.email && u.password === formData.password);
        if (user) {
          // Migration: convert nfts to nodes if needed
          const { password, ...safeUser } = user;
          if (safeUser.nfts && !safeUser.nodes) {
            safeUser.nodes = safeUser.nfts;
            delete safeUser.nfts;
          }
          localStorage.setItem('exza_current_user', JSON.stringify(safeUser));
          onAuthSuccess(safeUser as UserData);
          onClose();
        } else {
          setError('Invalid institutional credentials.');
        }
      } else {
        if (savedUsers.some((u: any) => u.email === formData.email)) {
          setError('Email address already exists in the node registry.');
          setLoading(false);
          return;
        }

        // Handle referral link logic
        let referredBy = '';
        if (formData.referral) {
          const referrer = savedUsers.find((u: any) => u.referralCode === formData.referral.trim().toUpperCase());
          if (referrer) {
            referredBy = referrer.email;
            // Update referrer member count
            referrer.referrals = (referrer.referrals || 0) + 1;
            localStorage.setItem('exza_users', JSON.stringify(savedUsers));
          } else {
            setError('Invalid referral code provided.');
            setLoading(false);
            return;
          }
        }

        const newUser: UserData = {
          username: formData.username,
          email: formData.email,
          tier: 'Basic',
          balance: 1000, // Pre-fund simulation
          referralCode: `EXZA-${Math.random().toString(36).substring(7).toUpperCase()}`,
          referrals: 0,
          referralEarnings: 0,
          referredBy: referredBy,
          nodes: [],
          // Fix: Added missing transactions property to match UserData interface
          transactions: []
        };

        const storageUser = { ...newUser, password: formData.password };
        savedUsers.push(storageUser);
        localStorage.setItem('exza_users', JSON.stringify(savedUsers));
        localStorage.setItem('exza_current_user', JSON.stringify(newUser));

        onAuthSuccess(newUser);
        onClose();
      }
    } catch (err) {
      setError('Network synchronization error.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={onClose} className="absolute inset-0 bg-exza-dark/95 backdrop-blur-md" />

          <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative w-full max-w-md glass-panel rounded-[2.5rem] border border-exza-gold/20 p-8 shadow-2xl overflow-hidden">
            <div className="absolute -top-24 -right-24 w-48 h-48 bg-exza-gold/10 blur-[80px] rounded-full" />

            <div className="text-center mb-8">
              <h2 className="text-3xl font-display font-bold text-white">{isLogin ? 'Portal Access' : 'Node Registry'}</h2>
              <p className="text-stone-500 text-sm mt-2">{isLogin ? 'Enter your secure credentials' : 'Join the quantum node ecosystem'}</p>
            </div>

            {error && (
              <div className="mb-6 p-3 bg-red-500/10 border border-red-500/20 text-red-400 text-[10px] font-black uppercase tracking-widest rounded-xl text-center">
                {error}
              </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-4">
              {!isLogin && (
                <div className="space-y-1">
                  <div className="relative">
                    <User className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-600" size={18} />
                    <input required type="text" placeholder="Institutional Username" className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white focus:border-exza-gold/50 outline-none transition-all text-sm" value={formData.username} onChange={e => setFormData({ ...formData, username: e.target.value })} />
                  </div>
                </div>
              )}

              <div className="space-y-1">
                <div className="relative">
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-600" size={18} />
                  <input required type="email" placeholder="Institutional Email" className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white focus:border-exza-gold/50 outline-none transition-all text-sm" value={formData.email} onChange={e => setFormData({ ...formData, email: e.target.value })} />
                </div>
              </div>

              <div className="space-y-1">
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-600" size={18} />
                  <input required type="password" placeholder="Access Password" className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white focus:border-exza-gold/50 outline-none transition-all text-sm" value={formData.password} onChange={e => setFormData({ ...formData, password: e.target.value })} />
                </div>
              </div>

              {!isLogin && (
                <div className="space-y-1">
                  <div className="relative">
                    <UserPlus className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-600" size={18} />
                    <input type="text" placeholder="Referral Code (Optional)" className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white focus:border-exza-gold/50 outline-none transition-all text-sm" value={formData.referral} onChange={e => setFormData({ ...formData, referral: e.target.value })} />
                  </div>
                </div>
              )}

              <button disabled={loading} type="submit" className="w-full py-5 bg-exza-gold text-exza-dark rounded-2xl font-black text-sm uppercase tracking-widest hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-xl shadow-exza-gold/10">
                {loading ? <RefreshCw className="animate-spin" size={20}/> : (isLogin ? 'Authorize Entry' : 'Register Node')}
              </button>
            </form>

            <button onClick={() => setIsLogin(!isLogin)} className="w-full mt-6 text-xs text-stone-500 hover:text-white transition-colors uppercase font-black tracking-widest">
              {isLogin ? "Request New Registration" : "I have an existing portal account"}
            </button>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

