                          <td className="px-8 py-6"><span className="px-3 py-1 bg-emerald-500/10 text-emerald-500 rounded-full text-[9px] font-black uppercase border border-emerald-500/20">SETTLED</span></td>
                          <td className="px-8 py-6 text-stone-600 font-mono text-[10px]">DAILY CYCLE</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
             </div>
           </div>
        )}
      </div>
    </div>
  );
};

