import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Wallet, TrendingUp, Users, ArrowUpRight, ArrowDownLeft, 
  Cpu, Zap, ShieldCheck, Copy, RefreshCw, 
  History, Gift, Percent, Gem, Award, Star, ShoppingBag, 
  X, CheckCircle2, DollarSign, Upload, Image as ImageIcon,
  CreditCard, ExternalLink, Check, Activity, BarChart3
} from 'lucide-react';
import { UserData, Transaction } from '../App';

export const UserDashboard: React.FC<{ user: UserData; onUpdate: (user: UserData) => void }> = ({ user, onUpdate }) => {
  const [activeTab, setActiveTab] = useState('overview');
  const [isMinting, setIsMinting] = useState(false);
  const [isDepositOpen, setIsDepositOpen] = useState(false);
  const [isWithdrawOpen, setIsWithdrawOpen] = useState(false);
  const [depositAmount, setDepositAmount] = useState('');
  const [withdrawAmount, setWithdrawAmount] = useState('');
  const [walletAddress, setWalletAddress] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);
  const [screenshot, setScreenshot] = useState<string | null>(null);
  const [liveProfit, setLiveProfit] = useState<number>(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const TRC20_WALLET = "AIzaSyBFedaweqD4YHAxg3F-NAPLRiHatWZiT-Y";
  const BEP20_WALLET = "0x3a1eddc8b626b83247de8edf85e1f850b5ef02b5";

  const exzaEarnPackages = [
    { id: 1, name: 'Core Node', price: 50, ratio: '1x', dailyPct: 1.0, color: 'from-stone-500 to-stone-400', icon: Cpu },
    { id: 2, name: 'Silver Node', price: 100, ratio: '2x', dailyPct: 1.2, color: 'from-blue-400 to-cyan-500', icon: Star },
    { id: 3, name: 'Gold Node', price: 250, ratio: '5x', dailyPct: 1.5, color: 'from-amber-400 to-exza-gold', icon: Award },
    { id: 4, name: 'Platinum Node', price: 500, ratio: '10x', dailyPct: 1.8, color: 'from-indigo-500 to-purple-600', icon: ShieldCheck },
    { id: 5, name: 'Diamond Node', price: 1000, ratio: '20x', dailyPct: 2.0, color: 'from-rose-500 to-pink-600', icon: Gem },
  ];

  // Simulation of daily profit accruing in real-time
  useEffect(() => {
    const dailyTotal = user.nodes?.reduce((acc, curr) => acc + (curr.price * curr.dailyPct / 100), 0) || 0;
    if (dailyTotal <= 0) {
      setLiveProfit(0);
      return;
    }

    // We assume 86400 seconds in a day. 
    // This adds a small fraction of the daily total every second for visual "profit"
    const increment = dailyTotal / 86400;

    const interval = setInterval(() => {
      setLiveProfit(prev => prev + increment);
    }, 1000);

    return () => clearInterval(interval);
  }, [user.nodes]);

  const calculateDailyTotal = () => {
    return (user.nodes?.reduce((acc, curr) => acc + (curr.price * curr.dailyPct / 100), 0) || 0).toFixed(2);
  };

  const handleMint = async (pkg: any) => {
    if (user.balance < pkg.price) {
      alert("Insufficient USDT balance. Please make a deposit and wait for institutional approval.");
      return;
    }

    setIsMinting(true);
    await new Promise(r => setTimeout(r, 2000));

    const updatedUser = {
      ...user,
      balance: user.balance - pkg.price,
      nodes: [...(user.nodes || []), { 
        ...pkg, 
        purchaseDate: new Date().toISOString(), 
        status: 'Active' 
      }]
    };

    if (user.referredBy) {
      const savedUsers = JSON.parse(localStorage.getItem('exza_users') || '[]');
      const referrerL1 = savedUsers.find((u: any) => u.email === user.referredBy);

      if (referrerL1) {
        const comm = pkg.price * 0.10;
        referrerL1.balance += comm;
        referrerL1.referralEarnings = (referrerL1.referralEarnings || 0) + comm;

        const hasGoldPlus = (referrerL1.nodes || referrerL1.nfts || []).some((n: any) => n.price >= 250);
        if (hasGoldPlus && referrerL1.referredBy) {
          const referrerL2 = savedUsers.find((u: any) => u.email === referrerL1.referredBy);
          if (referrerL2) {
            const commL2 = pkg.price * 0.05;
            referrerL2.balance += commL2;
            referrerL2.referralEarnings = (referrerL2.referralEarnings || 0) + commL2;
          }
        }
      }
      localStorage.setItem('exza_users', JSON.stringify(savedUsers));
    }

    onUpdate(updatedUser);
    setIsMinting(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setScreenshot(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopyStatus(id);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const submitDeposit = async (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseFloat(depositAmount);
    if (isNaN(amount) || amount < 20) {
      alert("Minimum deposit is $20 USDT");
      return;
    }
    if (!walletAddress) {
      alert("Sender wallet address required for verification.");
      return;
    }
    if (!screenshot) {
      alert("Screenshot of transfer confirmation required.");
      return;
    }

    setIsProcessing(true);
    await new Promise(r => setTimeout(r, 2000));

    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      type: 'DEPOSIT',
      amount,
      address: walletAddress,
      screenshot: screenshot,
      status: 'PENDING',
      date: new Date().toISOString()
    };

    onUpdate({
      ...user,
      transactions: [newTx, ...(user.transactions || [])]
    });

    setIsProcessing(false);
    setIsDepositOpen(false);
    setDepositAmount('');
    setWalletAddress('');
    setScreenshot(null);
    alert("Inbound transfer submitted for institutional verification. Balance will update once approved by Admin.");
  };

  const submitWithdrawal = async (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseFloat(withdrawAmount);
    if (isNaN(amount) || amount < 10) {
      alert("Minimum withdrawal is $10 USDT");
      return;
    }
    if (amount > user.balance) {
      alert("Insufficient balance.");
      return;
    }
    if (!walletAddress) {
      alert("Destination wallet address required.");
      return;
    }

    setIsProcessing(true);
    await new Promise(r => setTimeout(r, 2000));

    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      type: 'WITHDRAWAL',
      amount,
      address: walletAddress,
      status: 'PENDING',
      date: new Date().toISOString()
    };

    onUpdate({
      ...user,
      balance: user.balance - amount,
      transactions: [newTx, ...(user.transactions || [])]
    });

    setIsProcessing(false);
    setIsWithdrawOpen(false);
    setWithdrawAmount('');
    setWalletAddress('');
    alert("Withdrawal request initiated. Processing cycle: 24-48 hours.");
  };

  const copyRef = () => {
    navigator.clipboard.writeText(`https://exzaearn.com/join?ref=${user.referralCode}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="container mx-auto px-4 py-8 max-w-7xl">
      {/* Deposit Modal */}
      <AnimatePresence>
        {isDepositOpen && (
          <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => !isProcessing && setIsDepositOpen(false)} className="absolute inset-0 bg-exza-dark/95 backdrop-blur-xl" />
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative w-full max-w-lg glass-panel rounded-[2.5rem] border border-exza-gold/20 p-8 shadow-2xl overflow-hidden max-h-[90vh] overflow-y-auto">
              <button disabled={isProcessing} onClick={() => setIsDepositOpen(false)} className="absolute top-6 right-6 text-stone-500 hover:text-white transition-colors"><X size={24} /></button>
              <div className="text-center mb-6">
                <div className="w-16 h-16 bg-exza-gold/10 rounded-2xl flex items-center justify-center text-exza-gold mx-auto mb-4"><ArrowUpRight size={32} /></div>
                <h3 className="text-2xl font-display font-bold text-white">Institutional Deposit</h3>
                <p className="text-stone-500 text-sm mt-2">Transfer USDT to the platform wallets below</p>
              </div>

              {/* Platform Deposit Addresses */}
              <div className="space-y-4 mb-8">
                <div className="p-4 bg-white/5 rounded-2xl border border-white/10 space-y-2">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-black uppercase text-stone-500 tracking-widest">TRC20 WALLET</span>
                    <button 
                      onClick={() => copyToClipboard(TRC20_WALLET, 'trc')}
                      className="text-exza-gold hover:text-white transition-colors"
                    >
                      {copyStatus === 'trc' ? <Check size={14}/> : <Copy size={14}/>}
                    </button>
                  </div>
                  <p className="text-xs font-mono text-white break-all">{TRC20_WALLET}</p>
                </div>
                <div className="p-4 bg-white/5 rounded-2xl border border-white/10 space-y-2">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-black uppercase text-stone-500 tracking-widest">BEP20_WALLET</span>
                    <button 
                      onClick={() => copyToClipboard(BEP20_WALLET, 'bep')}
                      className="text-exza-gold hover:text-white transition-colors"
                    >
                      {copyStatus === 'bep' ? <Check size={14}/> : <Copy size={14}/>}
                    </button>
                  </div>
                  <p className="text-xs font-mono text-white break-all">{BEP20_WALLET}</p>
                </div>
              </div>

              <div className="w-full h-px bg-white/5 mb-8" />

              <form onSubmit={submitDeposit} className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-stone-500 tracking-widest px-1">USDT Amount (Min $20)</label>
                  <div className="relative">
                    <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 text-exza-gold" size={18} />
                    <input required type="number" placeholder="0.00" min="20" className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white focus:border-exza-gold/50 outline-none transition-all text-sm font-bold" value={depositAmount} onChange={e => setDepositAmount(e.target.value)} disabled={isProcessing} />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-stone-500 tracking-widest px-1">Your Sender Wallet Address</label>
                  <div className="relative">
                    <CreditCard className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-500" size={18} />
                    <input required type="text" placeholder="0x..." className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white focus:border-exza-gold/50 outline-none transition-all text-xs font-mono" value={walletAddress} onChange={e => setWalletAddress(e.target.value)} disabled={isProcessing} />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-stone-500 tracking-widest px-1">Transfer Screenshot</label>
                  <div onClick={() => fileInputRef.current?.click()} className="group cursor-pointer relative w-full aspect-video rounded-2xl bg-white/5 border-2 border-dashed border-white/10 hover:border-exza-gold/30 flex flex-col items-center justify-center transition-all overflow-hidden">
                    {screenshot ? (
                      <img src={screenshot} alt="Preview" className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" />
