                    )}
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
                  </div>
                </div>
                <button disabled={isProcessing} type="submit" className="w-full py-5 bg-exza-gold text-exza-dark rounded-2xl font-black text-sm uppercase tracking-widest hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-xl shadow-exza-gold/10">
                  {isProcessing ? <RefreshCw className="animate-spin" size={20}/> : 'Submit Verification Request'}
                </button>
