  id: string;
  type: 'DEPOSIT' | 'WITHDRAWAL';
  amount: number;
  status: 'PENDING' | 'COMPLETED' | 'FAILED';
  date: string;
  address: string;
  screenshot?: string;
}

export interface UserData {
  username: string;
  email: string;
  tier: string;
  balance: number;
  referralCode: string;
  referrals: number;
  referralEarnings: number;
  referredBy?: string;
