  Wallet, TrendingUp, Users, ArrowUpRight, ArrowDownLeft, 
  Cpu, Zap, ShieldCheck, Copy, RefreshCw, 
  History, Gift, Percent, Gem, Award, Star, ShoppingBag, 
  X, CheckCircle2, DollarSign, Upload, Image as ImageIcon,
  CreditCard, ExternalLink, Check, Activity, BarChart3, Plus,
  Settings, LogOut, User as UserIcon
} from 'lucide-react';
