import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Users, DollarSign, Activity, Settings, 
  Pause, Play, AlertTriangle, ShieldCheck, 
  Trash2, Database, X, Save, CheckCircle2, 
  XCircle, Image as ImageIcon, ArrowUpRight, 
  ArrowDownLeft, Clock, Eye, Copy, ExternalLink
} from 'lucide-react';
import { UserData, Transaction } from '../App';

interface ExtendedUserData extends UserData {
  password?: string;
  status?: 'Verified' | 'Pending' | 'Suspended';
}

interface PendingTx extends Transaction {
  userEmail: string;
  username: string;
}

export const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'users' | 'transactions'>('users');
  const [systemActive, setSystemActive] = useState(true);
  const [users, setUsers] = useState<ExtendedUserData[]>([]);
  const [editingUser, setEditingUser] = useState<ExtendedUserData | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [selectedScreenshot, setSelectedScreenshot] = useState<string | null>(null);
  const [stats, setStats] = useState({
    tvl: 0,
    payouts: 0,
    users: 0,
    nodes: 0
  });

  const loadData = useCallback(() => {
    const savedUsers = JSON.parse(localStorage.getItem('exza_users') || '[]');
    setUsers(savedUsers);

    const totalBalance = savedUsers.reduce((acc: number, u: ExtendedUserData) => acc + (u.balance || 0), 0);
    const totalExzaValue = savedUsers.reduce((acc: number, u: ExtendedUserData) => 
      acc + ((u.nodes || u.nfts || []).reduce((nAcc, n) => nAcc + n.price, 0) || 0), 0);
    const totalNodes = savedUsers.reduce((acc: number, u: ExtendedUserData) => acc + ((u.nodes || u.nfts || []).length || 0), 0);
    const totalEarnings = savedUsers.reduce((acc: number, u: ExtendedUserData) => acc + (u.referralEarnings || 0), 0);

    setStats({
      tvl: totalBalance + totalExzaValue,
      payouts: totalEarnings,
      users: savedUsers.length,
      nodes: totalNodes
    });
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  // Memoize pending transactions to avoid recalculation on every render
  const pendingTxs = useMemo(() => {
    const pending: PendingTx[] = [];
    users.forEach(u => {
      (u.transactions || []).forEach(tx => {
        if (tx.status === 'PENDING') {
          pending.push({ ...tx, userEmail: u.email, username: u.username });
        }
      });
    });
    return pending.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [users]);

  const handleTransactionAction = (txId: string, userEmail: string, action: 'APPROVE' | 'REJECT') => {
    const updatedUsers = users.map(u => {
      if (u.email === userEmail) {
        const updatedTxs = (u.transactions || []).map(tx => {
          if (tx.id === txId) {
            let finalStatus: 'COMPLETED' | 'FAILED' = action === 'APPROVE' ? 'COMPLETED' : 'FAILED';

            // Apply financial changes
            if (tx.type === 'DEPOSIT' && action === 'APPROVE') {
              u.balance += tx.amount;
            } else if (tx.type === 'WITHDRAWAL' && action === 'REJECT') {
              // Refund the balance that was deducted during request
              u.balance += tx.amount;
            }

            return { ...tx, status: finalStatus };
          }
          return tx;
        });
        return { ...u, transactions: updatedTxs };
      }
      return u;
    });

    localStorage.setItem('exza_users', JSON.stringify(updatedUsers));

    // Update current user session
    const currentUserStr = localStorage.getItem('exza_current_user');
    if (currentUserStr) {
      const currentUser = JSON.parse(currentUserStr);
      if (currentUser.email === userEmail) {
        const target = updatedUsers.find(u => u.email === userEmail);
        if (target) {
          const { password, ...safeUser } = target;
          localStorage.setItem('exza_current_user', JSON.stringify(safeUser));
        }
      }
    }

    loadData();
  };

  const handleDeleteUser = (email: string) => {
    if (email === 'admin@exza.com') {
      alert("Cannot delete root admin.");
      return;
    }
    if (window.confirm(`Delete account ${email}?`)) {
      const updatedUsers = users.filter(u => u.email !== email);
      localStorage.setItem('exza_users', JSON.stringify(updatedUsers));
      loadData();
    }
  };

  const handleEditClick = (user: ExtendedUserData) => {
    setEditingUser({ ...user });
    setIsEditModalOpen(true);
  };

  const handleSaveEdit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser) return;
    const updatedUsers = users.map(u => u.email === editingUser.email ? editingUser : u);
    localStorage.setItem('exza_users', JSON.stringify(updatedUsers));
    setIsEditModalOpen(false);
    loadData();
  };

  const copyToClipboard = useCallback((text: string) => {
    navigator.clipboard.writeText(text);
    alert("Address copied to clipboard.");
  }, []);

  return (
    <div className="container mx-auto px-4 py-8 max-w-7xl animate-fade-in">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
        <div>
          <h2 className="text-4xl font-display font-bold text-white mb-2">Institutional Management</h2>
          <p className="text-stone-500 text-sm tracking-wide">Command Center v4.2 // Real-time Operations Platform</p>
        </div>
        <div className="flex items-center gap-4">
          <div className={`px-4 py-2 rounded-full border flex items-center gap-2 text-[10px] font-black uppercase tracking-widest ${systemActive ? 'bg-emerald-500/10 border-emerald-500/50 text-emerald-400' : 'bg-red-500/10 border-red-500/50 text-red-400'}`}>
            <Activity size={12} /> {systemActive ? 'Network Active' : 'Maintenance Mode'}
          </div>
          <button 
            onClick={() => setSystemActive(!systemActive)}
            className={`p-3 rounded-xl transition-all shadow-lg ${systemActive ? 'bg-red-500 text-white shadow-red-500/20' : 'bg-emerald-500 text-white shadow-emerald-500/20'}`}
          >
            {systemActive ? <Pause size={20}/> : <Play size={20}/>}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
        {[
          { label: 'System TVL', value: `$${stats.tvl.toLocaleString()}`, icon: Database, color: 'text-blue-500' },
          { label: 'Total Payouts', value: `$${stats.payouts.toLocaleString()}`, icon: DollarSign, color: 'text-emerald-500' },
          { label: 'Node Holders', value: stats.users, icon: Users, color: 'text-purple-500' },
          { label: 'Deployed Nodes', value: stats.nodes, icon: ShieldCheck, color: 'text-exza-gold' }
        ].map((s, i) => (
          <div key={i} className="glass-panel p-6 rounded-3xl border border-white/5 bg-white/5 shadow-xl">
            <div className={`p-3 w-fit bg-white/5 rounded-xl ${s.color} mb-4`}><s.icon size={24}/></div>
            <p className="text-[10px] font-black text-stone-500 uppercase tracking-widest">{s.label}</p>
            <p className="text-3xl font-display font-bold text-white">{s.value}</p>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div className="flex gap-2 mb-8 bg-white/5 p-1 rounded-2xl w-fit">
        <button 
          onClick={() => setActiveTab('users')} 
          className={`px-8 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'users' ? 'bg-exza-gold text-exza-dark shadow-lg shadow-exza-gold/20' : 'text-stone-500 hover:text-white hover:bg-white/5'}`}
        >
          User Registry
        </button>
        <button 
          onClick={() => setActiveTab('transactions')} 
          className={`px-8 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all relative ${activeTab === 'transactions' ? 'bg-exza-gold text-exza-dark shadow-lg shadow-exza-gold/20' : 'text-stone-500 hover:text-white hover:bg-white/5'}`}
        >
          Transaction Queue
          {pendingTxs.length > 0 && (
            <span className="absolute -top-2 -right-2 bg-red-500 text-white text-[8px] w-5 h-5 flex items-center justify-center rounded-full border-2 border-exza-dark">
              {pendingTxs.length}
            </span>
          )}
        </button>
      </div>

      {activeTab === 'users' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 glass-panel rounded-3xl border border-white/5 overflow-hidden shadow-2xl">
            <div className="p-6 border-b border-white/5 flex justify-between items-center bg-white/5">
              <h3 className="text-lg font-bold text-white flex items-center gap-2"><Users size={20} className="text-exza-gold"/> Registry Data</h3>
              <span className="text-[10px] text-stone-500 font-black uppercase tracking-widest">{users.length} Registered Accounts</span>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[600px]">
                <thead className="bg-white/5 text-[10px] uppercase font-black tracking-widest text-stone-500">
                  <tr>
                    <th className="px-6 py-4">Node Profile</th>
                    <th className="px-6 py-4">Current Assets</th>
                    <th className="px-6 py-4">Verification</th>
                    <th className="px-6 py-4 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {users.map(u => (
                    <tr key={u.email} className="text-sm group hover:bg-white/5 transition-colors">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center text-exza-gold font-bold">{u.username.charAt(0)}</div>
                          <div>
                            <p className="text-white font-medium">{u.username}</p>
                            <p className="text-[10px] text-stone-500 font-mono tracking-tighter">{u.email}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <p className="font-display font-bold text-white">${(u.balance || 0).toLocaleString()}</p>
                        <p className="text-[9px] text-stone-500 uppercase font-black">{u.tier} Access</p>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-0.5 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                          u.status === 'Suspended' ? 'bg-red-500/10 border-red-500/30 text-red-500' :
                          'bg-emerald-500/10 border-emerald-500/30 text-emerald-400'
                        }`}>
                          {u.status || 'Verified'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex gap-2 justify-end opacity-40 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => handleEditClick(u)} className="p-2 text-stone-400 hover:text-white hover:bg-white/10 rounded-lg transition-all"><Settings size={18}/></button>
                          <button onClick={() => handleDeleteUser(u.email)} className="p-2 text-stone-400 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-all"><Trash2 size={18}/></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
          <div className="space-y-6">
            <div className="glass-panel p-8 rounded-3xl border border-white/5 bg-white/5">
              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2"><Clock size={20} className="text-blue-500"/> Activity Sync</h3>
              <div className="space-y-4">
                {[1, 2, 3, 4, 5].map(i => (
                  <div key={i} className="flex gap-3 text-[11px] items-center border-l-2 border-white/5 pl-4 py-1">
                    <span className="text-stone-600 font-mono italic">0{i}:4{i}</span>
                    <span className="text-stone-400">Node cluster {i} synchronization complete.</span>
                  </div>
