import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Mail, Lock, User, ShieldCheck, ArrowRight, UserPlus, ShieldAlert, Fingerprint } from 'lucide-react';
import { UserData } from '../App';

interface AuthProps {
  isOpen: boolean;
  onClose: () => void;
  onAuthSuccess: (user: UserData) => void;
}

export const AuthModal: React.FC<AuthProps> = ({ isOpen, onClose, onAuthSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: '',
    referral: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [securityStatus, setSecurityStatus] = useState('Standby');

  // Pre-initialize Admin account
  useEffect(() => {
    const savedUsers = JSON.parse(localStorage.getItem('exza_users') || '[]');
    if (!savedUsers.find((u: any) => u.email === 'admin@exza.com')) {
      const adminUser = {
        username: 'System Admin',
        email: 'admin@exza.com',
        password: 'admin123',
        tier: 'Platinum',
        balance: 1000000,
        referralCode: 'ADMIN-CORE',
        referrals: 150,
        referralEarnings: 0,
        nodes: [],
        transactions: []
      };
      savedUsers.push(adminUser);
      localStorage.setItem('exza_users', JSON.stringify(savedUsers));
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    setSecurityStatus('Encrypting...');

    // Simulate cryptographic delay
    await new Promise(resolve => setTimeout(resolve, 2000));

    try {
      const savedUsers = JSON.parse(localStorage.getItem('exza_users') || '[]');

      if (isLogin) {
        const user = savedUsers.find((u: any) => u.email.toLowerCase() === formData.email.toLowerCase() && u.password === formData.password);
        if (user) {
          setSecurityStatus('Authorized');
          const { password, ...safeUser } = user;
          localStorage.setItem('exza_current_user', JSON.stringify(safeUser));
          onAuthSuccess(safeUser as UserData);
          onClose();
        } else {
          setError('Authentication failed: Invalid institutional credentials.');
          setSecurityStatus('Access Denied');
        }
      } else {
        if (savedUsers.some((u: any) => u.email.toLowerCase() === formData.email.toLowerCase())) {
          setError('System Alert: Email already registered in the node network.');
          setSecurityStatus('Error');
          setLoading(false);
          return;
        }

        let referredBy = '';
        if (formData.referral) {
          const referrer = savedUsers.find((u: any) => u.referralCode === formData.referral.trim().toUpperCase());
          if (referrer) {
            referredBy = referrer.email;
            referrer.referrals = (referrer.referrals || 0) + 1;
          } else {
            setError('System Alert: Invalid institutional referral ID.');
            setSecurityStatus('Error');
            setLoading(false);
            return;
          }
        }

        const newUser: UserData = {
          username: formData.username,
          email: formData.email,
          tier: 'Basic',
          balance: 0,
          referralCode: `EXZA-${Math.random().toString(36).substring(7).toUpperCase()}`,
          referrals: 0,
          referralEarnings: 0,
          referredBy: referredBy,
          nodes: [],
          transactions: []
        };

        const storageUser = { ...newUser, password: formData.password };
        savedUsers.push(storageUser);
        localStorage.setItem('exza_users', JSON.stringify(savedUsers));

        // Auto-login after registration
        const { password, ...safeNewUser } = storageUser;
        localStorage.setItem('exza_current_user', JSON.stringify(safeNewUser));
        onAuthSuccess(safeNewUser as UserData);
        onClose();
      }
    } catch (err) {
      setError('Internal security protocol failure.');
      setSecurityStatus('System Error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={onClose} className="absolute inset-0 bg-exza-dark/95 backdrop-blur-md" />

          <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative w-full max-w-md glass-panel rounded-[2.5rem] border border-exza-gold/20 p-8 shadow-2xl overflow-hidden">
            <div className="absolute top-0 right-0 p-8 text-exza-gold/10"><ShieldCheck size={120} /></div>

            <div className="flex justify-between items-center mb-8 relative z-10">
               <div>
                  <h2 className="text-3xl font-display font-bold text-white">{isLogin ? 'Portal Auth' : 'Network Join'}</h2>
                  <div className="flex items-center gap-2 mt-1">
                    <span className={`w-2 h-2 rounded-full animate-pulse ${loading ? 'bg-amber-500' : 'bg-emerald-500'}`} />
                    <p className="text-stone-500 text-[10px] uppercase font-black tracking-widest">{securityStatus}</p>
                  </div>
               </div>
               <div className="p-3 bg-exza-gold/10 rounded-2xl text-exza-gold border border-exza-gold/20">
                  <Fingerprint size={24} />
               </div>
            </div>

            {error && (
              <motion.div initial={{ x: 20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} className="mb-6 p-4 bg-red-500/10 border border-red-500/20 text-red-400 text-[10px] font-black uppercase tracking-widest rounded-2xl flex items-center gap-3">
                <ShieldAlert size={16} />
                {error}
              </motion.div>
            )}

            <form onSubmit={handleSubmit} className="space-y-4 relative z-10">
              {!isLogin && (
                <div className="space-y-1">
                  <div className="relative group">
                    <User className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-600 group-focus-within:text-exza-gold transition-colors" size={18} />
                    <input required type="text" placeholder="Identity Username" className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white focus:border-exza-gold/50 focus:bg-white/10 outline-none transition-all text-sm" value={formData.username} onChange={e => setFormData({ ...formData, username: e.target.value })} />
                  </div>
                </div>
              )}

              <div className="space-y-1">
                <div className="relative group">
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-600 group-focus-within:text-exza-gold transition-colors" size={18} />
                  <input required type="email" placeholder="Institutional Email" className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white focus:border-exza-gold/50 focus:bg-white/10 outline-none transition-all text-sm" value={formData.email} onChange={e => setFormData({ ...formData, email: e.target.value })} />
                </div>
              </div>

              <div className="space-y-1">
                <div className="relative group">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-600 group-focus-within:text-exza-gold transition-colors" size={18} />
                  <input required type="password" placeholder="AES-256 Secret Key" className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white focus:border-exza-gold/50 focus:bg-white/10 outline-none transition-all text-sm" value={formData.password} onChange={e => setFormData({ ...formData, password: e.target.value })} />
                </div>
              </div>

              {!isLogin && (
                <div className="space-y-1">
                  <div className="relative group">
                    <UserPlus className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-600 group-focus-within:text-exza-gold transition-colors" size={18} />
                    <input type="text" placeholder="Referral ID (Optional)" className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white focus:border-exza-gold/50 focus:bg-white/10 outline-none transition-all text-sm" value={formData.referral} onChange={e => setFormData({ ...formData, referral: e.target.value })} />
                  </div>
                </div>
              )}

              <div className="pt-4">
                <button disabled={loading} type="submit" className="w-full py-5 bg-exza-gold text-exza-dark rounded-2xl font-black text-sm uppercase tracking-[0.2em] hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-3 shadow-xl shadow-exza-gold/10">
                  {loading ? <RefreshCw className="animate-spin" size={20}/> : (isLogin ? 'OPEN PORTAL' : 'INITIALIZE NODE')}
                  {!loading && <ShieldCheck size={18} />}
                </button>
              </div>
            </form>

            <div className="mt-8 flex flex-col gap-3">
               <button onClick={() => { setIsLogin(!isLogin); setError(''); }} className="w-full text-xs text-stone-500 hover:text-white transition-colors uppercase font-black tracking-widest text-center">
                  {isLogin ? "Switch to Node Registration" : "I have active credentials"}
               </button>
               <div className="w-full h-px bg-white/5" />
               <p className="text-[8px] text-stone-700 text-center font-black uppercase tracking-[0.3em]">SECURED BY EXZA QUANTUM CRYPTO SHIELD v4.0</p>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

