import React, { useState, useRef, useEffect, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Wallet, TrendingUp, Users, ArrowUpRight, ArrowDownLeft, 
  Cpu, Zap, ShieldCheck, Copy, RefreshCw, 
  History, Gift, Percent, Gem, Award, Star, ShoppingBag, 
  X, CheckCircle2, DollarSign, Upload, Image as ImageIcon,
  CreditCard, ExternalLink, Check, Activity, BarChart3, Plus,
  Settings, LogOut, User as UserIcon, Clock
} from 'lucide-react';
import { UserData, Transaction } from '../App';

const EXZA_EARN_PACKAGES = [
  { id: 1, name: 'Core Node', price: 50, ratio: '1.0x', dailyPct: 1.0, color: 'from-stone-500 to-stone-400', icon: Cpu },
  { id: 2, name: 'Silver Node', price: 100, ratio: '1.2x', dailyPct: 1.2, color: 'from-blue-400 to-cyan-500', icon: Star },
  { id: 3, name: 'Gold Node', price: 250, ratio: '1.5x', dailyPct: 1.5, color: 'from-amber-400 to-exza-gold', icon: Award },
  { id: 4, name: 'Platinum Node', price: 500, ratio: '1.8x', dailyPct: 1.8, color: 'from-indigo-500 to-purple-600', icon: ShieldCheck },
  { id: 5, name: 'Diamond Node', price: 1000, ratio: '2.0x', dailyPct: 2.0, color: 'from-rose-500 to-pink-600', icon: Gem },
];

const TRC20_WALLET = "AIzaSyBFedaweqD4YHAxg3F-NAPLRiHatWZiT-Y";
const BEP20_WALLET = "0x3a1eddc8b626b83247de8edf85e1f850b5ef02b5";
const NODE_DURATION_DAYS = 30;

export const UserDashboard: React.FC<{ user: UserData; onUpdate: (user: UserData) => void; onLogout?: () => void }> = ({ user, onUpdate, onLogout }) => {
  const [activeTab, setActiveTab] = useState('overview');
  const [isMinting, setIsMinting] = useState(false);
  const [isDepositOpen, setIsDepositOpen] = useState(false);
  const [isWithdrawOpen, setIsWithdrawOpen] = useState(false);
  const [depositAmount, setDepositAmount] = useState('');
  const [withdrawAmount, setWithdrawAmount] = useState('');
  const [walletAddress, setWalletAddress] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);
  const [screenshot, setScreenshot] = useState<string | null>(null);
  const [liveProfit, setLiveProfit] = useState<number>(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- AUTOMATIC NODE EXPIRY LOGIC ---
  useEffect(() => {
    const checkExpirations = () => {
      const now = new Date();
      let hasUpdates = false;
      let newBalance = user.balance;
      const activeNodes = user.nodes || [];

      const filteredNodes = activeNodes.filter(node => {
        const purchaseDate = new Date(node.purchaseDate);
        const diffTime = Math.abs(now.getTime() - purchaseDate.getTime());
        const diffDays = diffTime / (1000 * 60 * 60 * 24);

        if (diffDays >= NODE_DURATION_DAYS) {
          newBalance += node.price; // Refund principal
          hasUpdates = true;
          return false;
        }
        return true;
      });

      if (hasUpdates) {
        onUpdate({
          ...user,
          balance: newBalance,
          nodes: filteredNodes
        });
        alert("SYSTEM NOTICE: One or more Quantum Nodes have completed their 30-day operational cycle. Your principal investment has been automatically returned to your available balance.");
      }
    };

    checkExpirations();
    const interval = setInterval(checkExpirations, 60000); // Check every minute
    return () => clearInterval(interval);
  }, [user.nodes, user.balance, onUpdate]);

  const dailyTotal = useMemo(() => {
    return user.nodes?.reduce((acc, curr) => acc + (curr.price * curr.dailyPct / 100), 0) || 0;
  }, [user.nodes]);

  const dailyTotalFormatted = useMemo(() => dailyTotal.toFixed(2), [dailyTotal]);

  useEffect(() => {
    if (dailyTotal <= 0) {
      if (liveProfit !== 0) setLiveProfit(0);
      return;
    }
    const increment = dailyTotal / 86400;
    const interval = setInterval(() => {
      setLiveProfit(prev => prev + increment);
    }, 1000);
    return () => clearInterval(interval);
  }, [dailyTotal]);

  const handleMint = async (pkg: typeof EXZA_EARN_PACKAGES[0]) => {
    if (user.balance < pkg.price) {
      alert(`Insufficient balance. You need $${pkg.price} USDT to activate a ${pkg.name}.`);
      return;
    }

    setIsMinting(true);
    await new Promise(r => setTimeout(r, 2000));

    const updatedUser: UserData = {
      ...user,
      balance: user.balance - pkg.price,
      nodes: [...(user.nodes || []), { 
        ...pkg, 
        purchaseDate: new Date().toISOString(), 
        status: 'Active' 
      }]
    };

    if (user.referredBy) {
      const savedUsers = JSON.parse(localStorage.getItem('exza_users') || '[]');
      const referrerL1 = savedUsers.find((u: any) => u.email === user.referredBy);
      if (referrerL1) {
        const comm = pkg.price * 0.10;
        referrerL1.balance += comm;
        referrerL1.referralEarnings = (referrerL1.referralEarnings || 0) + comm;
        localStorage.setItem('exza_users', JSON.stringify(savedUsers));
      }
    }

    onUpdate(updatedUser);
    setIsMinting(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setScreenshot(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const copyToClipboard = useCallback((text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopyStatus(id);
    setTimeout(() => setCopyStatus(null), 2000);
  }, []);

  const submitDeposit = async (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseFloat(depositAmount);
    if (isNaN(amount) || amount < 20) {
      alert("Minimum deposit is $20 USDT");
      return;
    }
    if (!walletAddress || !screenshot) {
      alert("Verification details required.");
      return;
    }

    setIsProcessing(true);
    await new Promise(r => setTimeout(r, 2000));

    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      type: 'DEPOSIT',
      amount,
      address: walletAddress,
      screenshot: screenshot,
      status: 'PENDING',
      date: new Date().toISOString()
    };

    onUpdate({
      ...user,
      transactions: [newTx, ...(user.transactions || [])]
    });

    setIsProcessing(false);
    setIsDepositOpen(false);
    setDepositAmount('');
    setWalletAddress('');
    setScreenshot(null);
  };

  const submitWithdrawal = async (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseFloat(withdrawAmount);
    if (isNaN(amount) || amount < 10 || amount > user.balance) {
      alert("Invalid withdrawal amount.");
      return;
    }

    setIsProcessing(true);
    await new Promise(r => setTimeout(r, 2000));

    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      type: 'WITHDRAWAL',
      amount,
      address: walletAddress,
      status: 'PENDING',
      date: new Date().toISOString()
    };

    onUpdate({
      ...user,
      balance: user.balance - amount,
      transactions: [newTx, ...(user.transactions || [])]
    });

    setIsProcessing(false);
    setIsWithdrawOpen(false);
    setWithdrawAmount('');
    setWalletAddress('');
  };

  const copyRef = useCallback(() => {
    navigator.clipboard.writeText(`https://exzaearn.com/join?ref=${user.referralCode}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }, [user.referralCode]);

  // Helper to calculate days remaining
  const getDaysRemaining = (purchaseDateStr: string) => {
    const purchaseDate = new Date(purchaseDateStr);
    const now = new Date();
    const diffTime = now.getTime() - purchaseDate.getTime();
    const diffDays = diffTime / (1000 * 60 * 60 * 24);
    const remaining = Math.max(0, NODE_DURATION_DAYS - diffDays);
    return Math.ceil(remaining);
  };

  return (
    <div className="container mx-auto px-4 py-8 max-w-7xl">
      {/* Modals for Deposit/Withdrawal omitted for brevity in snippet, keeping functionality intact */}
      <AnimatePresence>
        {isDepositOpen && (
          <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => !isProcessing && setIsDepositOpen(false)} className="absolute inset-0 bg-exza-dark/95 backdrop-blur-xl" />
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative w-full max-w-lg glass-panel rounded-[2.5rem] border border-exza-gold/20 p-8 shadow-2xl overflow-hidden max-h-[90vh] overflow-y-auto">
              <button disabled={isProcessing} onClick={() => setIsDepositOpen(false)} className="absolute top-6 right-6 text-stone-500 hover:text-white transition-colors"><X size={24} /></button>
              <div className="text-center mb-6">
                <div className="w-16 h-16 bg-exza-gold/10 rounded-2xl flex items-center justify-center text-exza-gold mx-auto mb-4"><ArrowUpRight size={32} /></div>
                <h3 className="text-2xl font-display font-bold text-white">Institutional Deposit</h3>
                <p className="text-stone-500 text-sm mt-2">Transfer USDT to the platform wallets below</p>
              </div>
              <div className="space-y-4 mb-8">
                <div className="p-4 bg-white/5 rounded-2xl border border-white/10 space-y-2">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-black uppercase text-stone-500 tracking-widest">TRC20 WALLET</span>
                    <button onClick={() => copyToClipboard(TRC20_WALLET, 'trc')} className="text-exza-gold hover:text-white">
                      {copyStatus === 'trc' ? <Check size={14}/> : <Copy size={14}/>}
                    </button>
                  </div>
                  <p className="text-xs font-mono text-white break-all">{TRC20_WALLET}</p>
                </div>
              </div>
              <form onSubmit={submitDeposit} className="space-y-6">
                <div className="space-y-2">
                   <label className="text-[10px] font-black uppercase text-stone-500 tracking-widest px-1">USDT Amount (Min $20)</label>
                   <div className="relative">
                      <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 text-exza-gold" size={18} />
                      <input required type="number" placeholder="0.00" min="20" className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white outline-none" value={depositAmount} onChange={e => setDepositAmount(e.target.value)} />
                   </div>
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-black uppercase text-stone-500 tracking-widest px-1">Sender Wallet Address</label>
                   <input required type="text" placeholder="0x..." className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-4 text-white outline-none" value={walletAddress} onChange={e => setWalletAddress(e.target.value)} />
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-black uppercase text-stone-500 tracking-widest px-1">Transfer Screenshot</label>
                   <div onClick={() => fileInputRef.current?.click()} className="group cursor-pointer relative w-full aspect-video rounded-2xl bg-white/5 border-2 border-dashed border-white/10 flex flex-col items-center justify-center transition-all overflow-hidden">
                      {screenshot ? <img src={screenshot} alt="Preview" className="w-full h-full object-cover" /> : <Upload className="text-stone-500" size={32} />}
                      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
                   </div>
                </div>
                <button type="submit" className="w-full py-5 bg-exza-gold text-exza-dark rounded-2xl font-black text-sm uppercase tracking-widest">
                  {isProcessing ? 'Processing...' : 'Submit Deposit'}
                </button>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
