          <div className="flex items-center gap-2 cursor-pointer group" onClick={() => { setView('landing'); window.scrollTo({ top: 0, behavior: 'smooth' }); }}>
            <div className="w-10 h-10 bg-exza-gold rounded-xl flex items-center justify-center text-exza-dark font-display font-black text-xl shadow-[0_0_20px_rgba(197,160,89,0.3)] transition-transform group-hover:scale-110">E</div>
            <span className="font-display font-bold text-2xl tracking-tighter text-white">
              EXZA<span className="text-exza-gold">EARN</span>
            </span>
          </div>
          <div className="hidden lg:flex items-center gap-10 text-xs font-bold tracking-[0.15em] uppercase text-stone-400">
            {view === 'landing' ? (
              <>
                <a href="#yields" onClick={scrollToSection('yields')} className="hover:text-exza-gold transition-colors">Yields</a>
                <a href="#security" onClick={scrollToSection('security')} className="hover:text-exza-gold transition-colors">Security</a>
                <a href="#tiers" onClick={scrollToSection('tiers')} className="hover:text-exza-gold transition-colors">Benefits</a>
                <a href="#roadmap" onClick={scrollToSection('roadmap')} className="hover:text-exza-gold transition-colors">Roadmap</a>
              </>
            ) : (
              <button onClick={() => setView('landing')} className="hover:text-white transition-colors">Home</button>
            )}
            {currentUser ? (
              <div className="flex items-center gap-6">
                <button 
                  onClick={() => setView(currentUser.email === 'admin@exza.com' ? 'admin' : 'dashboard')}
                  className="flex flex-col items-end group"
                >
                  <span className="text-white font-black text-[10px] tracking-widest flex items-center gap-1 group-hover:text-exza-gold">
                    <LayoutGrid size={12}/> PORTAL
                  </span>
                  <span className="text-stone-500 text-[9px]">{currentUser.tier} Tier</span>
                </button>
                <button onClick={handleLogout} className="p-2.5 bg-white/5 text-stone-400 rounded-full hover:bg-white/10 transition-all border border-white/10"><LogOut size={16} /></button>
              </div>
            ) : (
              <button onClick={() => setIsAuthOpen(true)} className="px-6 py-2.5 bg-exza-gold text-exza-dark rounded-full hover:bg-white transition-all shadow-lg font-black flex items-center gap-2">START EARNING <Zap size={14} fill="currentColor" /></button>
            )}
          </div>
          <button className="lg:hidden text-white p-2" onClick={() => setMenuOpen(!menuOpen)}>{menuOpen ? <X size={28} /> : <Menu size={28} />}</button>
        </div>
      </nav>
      <div className="pt-20">
        {view === 'landing' && (
          <div className="animate-fade-in">
            <header className="relative min-h-screen flex items-center justify-center pt-20 overflow-hidden">
              <CryptoHeroScene />
              <div className="absolute top-1/4 -left-20 w-96 h-96 bg-exza-gold/10 blur-[120px] rounded-full pointer-events-none" />
              <div className="absolute bottom-1/4 -right-20 w-96 h-96 bg-emerald-500/5 blur-[120px] rounded-full pointer-events-none" />
              <div className="relative z-10 container mx-auto px-6 text-center">
                <div className="inline-flex items-center gap-2 mb-6 px-4 py-1.5 border border-exza-gold/20 text-exza-gold text-[10px] tracking-[0.3em] uppercase font-black rounded-full backdrop-blur-md bg-exza-gold/5">
                  <ShieldCheck size={12} /> Institutional Grade Digital Assets
