                <h1 className="font-display text-6xl md:text-8xl lg:text-[10rem] font-bold leading-[0.85] mb-8 text-white tracking-tighter">QUANTUM <br/><span className="gold-gradient italic">EARNINGS</span></h1>
                <p className="max-w-3xl mx-auto text-lg md:text-xl text-stone-400 font-light leading-relaxed mb-12">Own a piece of the network. Deploy Exza Nodes and receive real-time USDT settlements directly to your institutional wallet.</p>
                <div className="flex flex-col sm:flex-row justify-center gap-4">
                  <button onClick={() => currentUser ? setView('dashboard') : setIsAuthOpen(true)} className="px-10 py-5 bg-exza-gold text-exza-dark rounded-full font-black text-lg hover:scale-105 transition-transform flex items-center justify-center gap-3 shadow-[0_0_30px_rgba(197,160,89,0.3)]">{currentUser ? 'GO TO DASHBOARD' : 'OPEN ACCOUNT'} <ArrowRight size={20} /></button>
                  <button className="px-10 py-5 bg-white/5 border border-white/10 text-white rounded-full font-bold text-lg hover:bg-white/10 transition-colors backdrop-blur-md">VIEW AUDIT</button>
                </div>
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mt-24">
                  <MetricCard label="Total Nodes" value="12,450" subtext="Global Hashrate" />
                  <MetricCard label="TVL Secured" value="$42M+" subtext="Locked in Contracts" />
