  const [isAiLoading, setIsAiLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- NODE EXPIRY MONITOR (FIXED FOR #185) ---
  useEffect(() => {
    const checkExpirations = () => {
      const now = Date.now();
      let hasExpired = false;
      let totalRefund = 0;
      const nodes = user.nodes || [];

      const updatedNodes = nodes.filter(node => {
        const purchaseTime = new Date(node.purchaseDate).getTime();
        const ageInDays = (now - purchaseTime) / (1000 * 60 * 60 * 24);

        if (ageInDays >= NODE_DURATION_DAYS) {
          hasExpired = true;
          totalRefund += node.price;
          return false;
        }
        return true;
      });

      if (hasExpired) {
        onUpdate({
          ...user,
          balance: user.balance + totalRefund,
          nodes: updatedNodes
        });
      }
    };

    const interval = setInterval(checkExpirations, 10000); // Check every 10 seconds
    return () => clearInterval(interval);
  }, [user, onUpdate]);

  const dailyTotal = useMemo(() => {
    return user.nodes?.reduce((acc, curr) => acc + (curr.price * curr.dailyPct / 100), 0) || 0;
  }, [user.nodes]);

  useEffect(() => {
    if (dailyTotal <= 0) return;
    const increment = dailyTotal / 86400;
    const interval = setInterval(() => {
      setLiveProfit(prev => prev + increment);
    }, 1000);
    return () => clearInterval(interval);
  }, [dailyTotal]);

  const handleMint = async (pkg: typeof EXZA_EARN_PACKAGES[0]) => {
    if (user.balance < pkg.price) {
      alert(`Insufficient balance. You need $${pkg.price} USDT.`);
      return;
    }

    setIsMinting(true);
    await new Promise(r => setTimeout(r, 1500));

    onUpdate({
      ...user,
      balance: user.balance - pkg.price,
      nodes: [...(user.nodes || []), { 
        ...pkg, 
        purchaseDate: new Date().toISOString(), 
        status: 'Active' 
      }]
    });
    setIsMinting(false);
  };

  const handleAiChat = async () => {
    if (!aiMessage.trim()) return;

    const prompt = aiMessage;
    setChatHistory(prev => [...prev, { role: 'user', text: prompt }]);
    setAiMessage('');
    setIsAiLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction: `You are the EXZA EARN Quantum AI Support. 
          You assist users with their institutional crypto node platform.
          Rules:
          - User Balance: $${user.balance}.
          - Active Nodes: ${user.nodes?.length || 0}.
