  const getDaysRemaining = (dateStr: string) => {
    const diff = (Date.now() - new Date(dateStr).getTime()) / (1000 * 60 * 60 * 24);
    return Math.max(0, Math.ceil(NODE_DURATION_DAYS - diff));
